     1|/**
     2| * IVX Senior-Developer Answer Format
     3| *
     4| * Renders the senior-developer runtime proof into the OWNER-REQUIRED strict
     5| * execution format. The owner explicitly rejected narrative prose ("Owner
     6| * Execution Mode — executing end-to-end…"); every development task must return
     7| * an evidence-only block:
     8| *
     9| *   TASK UNDERSTOOD / FILES INSPECTED / FILES CHANGED / COMMANDS RUN /
    10| *   TEST RESULT / TYPECHECK RESULT / STATUS / PROOF
    11| *
    12| * Hard enforcement (no claims without real commands):
    13| *   - No files changed      → "NO CODE CHANGED — no development was completed."
    14| *   - No tests run          → "NOT VERIFIED — tests were not run."
    15| *   - Patch could not write  → "BLOCKED — I do not have code write access."
    16| *
    17| * This module is runtime-free and deterministic (no network/filesystem/AI) so it
    18| * is fully unit-testable.
    19| */
    20|import type { IVXSeniorDeveloperRunProof } from './ivx-senior-developer-runtime';
    21|import type { IVXOwnerExecutionDecision } from './ivx-owner-execution-mode';
    22|
    23|function trimmed(value: unknown): string {
    24|  return typeof value === 'string' ? value.trim() : '';
    25|}
    26|
    27|function firstSentence(text: string): string {
    28|  const normalized = trimmed(text).replace(/\s+/g, ' ');
    29|  if (!normalized) {
    30|    return 'Execute the requested development task.';
    31|  }
    32|  const sentence = normalized.split(/(?<=[.!?])\s/)[0] ?? normalized;
    33|  return sentence.length > 160 ? `${sentence.slice(0, 157)}...` : sentence;
    34|}
    35|
    36|/** Render one validation result as raw, copy-pasteable terminal output. */
    37|function rawValidationOutput(validation: IVXSeniorDeveloperRunProof['validations'][number]): string {
    38|  return [
    39|    `$ ${validation.command}`,
    40|    validation.stdoutTail ? validation.stdoutTail.trimEnd() : '',
    41|    validation.stderrTail ? validation.stderrTail.trimEnd() : '',
    42|    validation.error ? `error: ${validation.error}` : '',
    43|    `exit code: ${validation.exitCode ?? 'null'} → ${validation.ok ? 'PASS' : 'FAIL'}`,
    44|  ]
    45|    .filter((line) => line.length > 0)
    46|    .join('\n');
    47|}
    48|
    49|export function isTypecheckCommand(command: string): boolean {
    50|  return /\b(tsc|typecheck|type-check|type\s+check)\b/i.test(command);
    51|}
    52|
    53|export function isTestCommand(command: string): boolean {
    54|  return /\btest\b/i.test(command) && !isTypecheckCommand(command);
    55|}
    56|
    57|/**
    58| * Build the senior-developer execution answer in the owner-required strict format.
    59| */
    60|export function buildSeniorDeveloperExecutionAnswer(
    61|  proof: IVXSeniorDeveloperRunProof,
    62|  decision: IVXOwnerExecutionDecision,
    63|): string {
    64|  // Guarded actions are the only path allowed to stop before executing.
    65|  if (decision.requiresApproval) {
    66|    const categories = decision.approvalCategories.join(', ') || 'a guarded action';
    67|    return [
    68|      `TASK UNDERSTOOD:\n${firstSentence(proof.goal)}`,
    69|      `FILES INSPECTED:\n${proof.repoBrain.keyFiles.slice(0, 12).join('\n') || 'none'}`,
    70|      'FILES CHANGED:\nNO CODE CHANGED — no development was completed.',
    71|      'COMMANDS RUN:\nnone — guarded action requires explicit owner confirmation before execution.',
    72|      'TEST RESULT:\nNOT VERIFIED — tests were not run.',
    73|      'TYPECHECK RESULT:\nNOT VERIFIED — typecheck was not run.',
    74|      'STATUS:\nBLOCKED',
    75|      `PROOF:\nBLOCKED — requires owner confirmation: ${categories}. Reply with the exact action and confirmation text to execute.`,
    76|    ].join('\n\n');
    77|  }
    78|
    79|  const changedFiles = proof.changedFiles;
    80|  const validations = proof.validations;
    81|  const testValidations = validations.filter((v) => isTestCommand(v.command));
    82|  const typecheckValidations = validations.filter((v) => isTypecheckCommand(v.command));
    83|  const otherValidations = validations.filter(
    84|    (v) => !isTestCommand(v.command) && !isTypecheckCommand(v.command),
    85|  );
    86|  const git = proof.gitDeployOperator;
    87|
    88|  // FILES INSPECTED — real paths the repo brain indexed for this task.
    89|  const inspected = proof.repoBrain.keyFiles.slice(0, 12);
    90|  const filesInspected = inspected.length > 0
    91|    ? inspected.join('\n')
    92|    : `indexed ${proof.repoBrain.indexedFileCount} files across ${proof.repoBrain.indexedDirectoryCount} directories`;
    93|
    94|  // FILES CHANGED — hard enforcement: real paths or the exact "no change" / "no write" line.
    95|  let filesChanged: string;
    96|  if (changedFiles.length > 0) {
    97|    filesChanged = changedFiles.join('\n');
    98|  } else if (proof.patchProposal.status === 'blocked') {
    99|    filesChanged = 'BLOCKED — I do not have code write access.';
   100|  } else {
   101|    filesChanged = 'NO CODE CHANGED — no development was completed.';
   102|  }
   103|
   104|  // COMMANDS RUN — raw command lines actually executed (validations + git/deploy).
   105|  const commandLines: string[] = otherValidations
   106|    .concat(testValidations, typecheckValidations)
   107|    .map((v) => `$ ${v.command} → exit ${v.exitCode ?? 'null'} (${v.ok ? 'PASS' : 'FAIL'})`);
   108|  if (git.github.commitAttempted) {
   109|    commandLines.push(`$ git commit/push → ${git.github.commitSha ? `committed ${git.github.commitSha}` : `not completed (${git.reason})`}`);
   110|  }
   111|  if (git.render.deployAttempted) {
   112|    commandLines.push(`$ render deploy → ${git.render.deployId ? `${git.render.deployStatus ?? 'triggered'} (${git.render.deployId})` : `not completed (${git.render.error ?? git.reason})`}`);
   113|  }
   114|  const commandsRun = commandLines.length > 0
   115|    ? commandLines.join('\n')
   116|    : 'NONE — no commands were executed.';
   117|
   118|  // TEST RESULT — raw output or the exact "not verified" line.
   119|  const testResult = testValidations.length > 0
   120|    ? testValidations.map(rawValidationOutput).join('\n\n')
   121|    : 'NOT VERIFIED — tests were not run.';
   122|
   123|  // TYPECHECK RESULT — raw output or the exact "not verified" line.
   124|  const typecheckResult = typecheckValidations.length > 0
   125|    ? typecheckValidations.map(rawValidationOutput).join('\n\n')
   126|    : 'NOT VERIFIED — typecheck was not run.';
   127|
   128|  // STATUS — DEPLOYED only when commit+deploy executed, production verified, AND
   129|  // the validation checks actually ran and passed. A deploy that looks complete
   130|  // but has no confirmed tests/typecheck is UNVERIFIED, never DEPLOYED — claiming
   131|  // DEPLOYED while tests/typecheck read "NOT VERIFIED" is exactly the dishonest
   132|  // mismatch this format must prevent.
   133|  const checksRan = testValidations.length > 0 || typecheckValidations.length > 0;
   134|  const checksPassed = checksRan && validations.every((v) => v.ok);
   135|  const deployConfirmed = git.status === 'executed'
   136|    && Boolean(git.github.commitSha)
   137|    && proof.productionVerification.ok
   138|    && proof.changedRouteVerification.ok;
   139|  let status: 'DEPLOYED' | 'UNVERIFIED' | 'LOCAL ONLY' | 'BLOCKED';
   140|  if (changedFiles.length === 0 || proof.patchProposal.status === 'blocked') {
   141|    status = 'BLOCKED';
   142|  } else if (deployConfirmed && checksPassed) {
   143|    status = 'DEPLOYED';
   144|  } else if (deployConfirmed && !checksPassed) {
   145|    // Deploy pipeline reported done, but checks were not run/confirmed — do not
   146|    // overclaim. Surface UNVERIFIED so the report matches the TEST/TYPECHECK lines.
   147|    status = 'UNVERIFIED';
   148|  } else {
   149|    status = 'LOCAL ONLY';
   150|  }
   151|
   152|  // PROOF — diff-stat-style summary derived from the applied patch operations.
   153|  const proofLines: string[] = [];
   154|  if (changedFiles.length > 0) {
   155|    proofLines.push('git diff --stat (applied patch):');
   156|    for (const filePath of changedFiles) {
   157|      const op = proof.patchProposal.operations.find((operation) => operation.path === filePath);
   158|      proofLines.push(` ${filePath} | ${op ? op.summary : 'modified'}`);
   159|    }
   160|    proofLines.push('git status --short:');
   161|    for (const filePath of changedFiles) {
   162|      proofLines.push(` M ${filePath}`);
   163|    }
   164|    if (git.github.commitSha) {
   165|      proofLines.push(`commit: ${git.github.commitSha}${git.github.branch ? ` (${git.github.branch})` : ''}`);
   166|    }
   167|    proofLines.push(`production /health: ${proof.productionVerification.ok ? 'healthy' : 'not confirmed'}; changed route: ${proof.changedRouteVerification.ok ? 'live' : 'not confirmed'}`);
   168|  } else {
   169|    proofLines.push('git diff --stat: (no changes)');
   170|    proofLines.push('git status --short: (clean)');
   171|  }
   172|  proofLines.push(`job: ${proof.jobId}`);
   173|
   174|  return [
   175|    `TASK UNDERSTOOD:\n${firstSentence(proof.goal)}`,
   176|    `FILES INSPECTED:\n${filesInspected}`,
   177|    `FILES CHANGED:\n${filesChanged}`,
   178|    `COMMANDS RUN:\n${commandsRun}`,
   179|    `TEST RESULT:\n${testResult}`,
   180|    `TYPECHECK RESULT:\n${typecheckResult}`,
   181|    `STATUS:\n${status}`,
   182|    `PROOF:\n${proofLines.join('\n')}`,
   183|  ].join('\n\n');
