   199|// ---------------------------------------------------------------------------
   200|// Prohibition scanner (requirement 4 + requirement 6)
   201|// ---------------------------------------------------------------------------
   202|
   203|export type ProhibitionViolation = {
   204|  rule: string;
   205|  snippet: string;
   206|  reason: string;
   207|};
   208|
   209|/**
   210| * Scan an answer string for hard-prohibition violations.
   211| * Pure function — no I/O, always returns the same result for the same input.
   212| */
   213|export function scanForProhibitions(answer: string, evidenceAvailable: boolean): ProhibitionViolation[] {
   214|  const violations: ProhibitionViolation[] = [];
   215|
   216|  // 1. Simulated data presented as real
   217|  if (!evidenceAvailable) {
   218|    // Check for commit claims when there's no evidence of a real commit
   219|    const commitMatch = COMMIT_REGEX.exec(answer);
   220|    if (commitMatch) {
   221|      violations.push({
   222|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   223|        snippet: commitMatch[0],
   224|        reason: 'Claims a commit was made but no commit evidence (github.commitSha) exists.',
   225|      });
   226|    }
   227|
   228|    // Check for deploy claims without deployment evidence
   229|    const deployMatch = DEPLOY_REGEX.exec(answer);
   230|    if (deployMatch) {
   231|      violations.push({
   232|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   233|        snippet: deployMatch[0],
   234|        reason: 'Claims deployment was performed but no deployment evidence (render.deployId) exists.',
   235|      });
   236|    }
   237|
   238|    // Check for code-change claims without changed-files evidence
   239|    const codeMatch = CODE_CHANGE_REGEX.exec(answer);
   240|    if (codeMatch) {
   241|      violations.push({
   242|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   243|        snippet: codeMatch[0],
   244|        reason: 'Claims code was changed but no changedFiles evidence exists.',
   245|      });
   246|    }
   247|
   248|    // Check for database mutation claims without DB evidence
   249|    const dbMatch = DB_MUTATION_REGEX.exec(answer);
   250|    if (dbMatch) {
   251|      violations.push({
   252|        rule: 'NO_SIMULATED_DATA_AS_REAL',
   253|        snippet: dbMatch[0],
   254|        reason: 'Claims a database mutation was performed but no DB-operation evidence exists.',
   255|      });
   256|    }
   257|  }
   258|
   259|  // 2. UUID presented as Git SHA
   260|  const uuidShaMatch = UUID_AS_SHA_REGEX.exec(answer);
   261|  if (uuidShaMatch) {
   262|    violations.push({
   263|      rule: 'NO_UUID_AS_GIT_SHA',
   264|      snippet: uuidShaMatch[0],
   265|      reason: `A UUID (${uuidShaMatch[1]}) is presented as a Git commit SHA.`,
   266|    });
   267|  }
   268|
   269|  // Now check non-UUID-format strings: if evidence is absent and the answer contains
   270|  // a GitHub-format hex string but the caller's evidence has no real SHA,
   271|  // that's also a violation.
   272|  if (!evidenceAvailable) {
   273|    const shaMatches = answer.matchAll(GIT_SHA_REGEX);
   274|    for (const match of shaMatches) {
   275|      const sha = match[0];
   276|      // Skip if it's clearly something else (like a UUID or a hex color in a non-commit context)
   277|      if (sha.length >= 7 && !uuidShaMatch && /\bcommit\b/i.test(answer.slice(Math.max(0, match.index! - 40), match.index! + sha.length + 10))) {
   278|        violations.push({
   279|          rule: 'NO_FAKE_GIT_SHA',
   280|          snippet: sha,
   281|          reason: 'A hex string resembling a Git SHA appears near commit language but no real commit evidence exists.',
   282|        });
   283|        break; // One is enough — don't flood
   284|      }
   285|    }
   286|  }
   287|
   288|  // 3. Deployment claim without provider confirmation
   289|  if (!evidenceAvailable) {
   290|    const deployWithProvider = /\b(Render|Vercel|AWS|Cloudflare|Netlify|Heroku)\s+(?:deploy|auto-deploy|build)/i.exec(answer);
   291|    if (deployWithProvider) {
   292|      violations.push({
   293|        rule: 'NO_DEPLOY_WITHOUT_PROVIDER_CONFIRMATION',
   294|        snippet: deployWithProvider[0],
   295|        reason: 'References a provider deployment but has no deploy confirmation evidence.',
   296|      });
   297|    }
   298|  }
   299|
   300|  // 4. Code change claimed without actual diff output
   301|  const diffMatch = FAKE_DIFF_REGEX.exec(answer);
   302|  if (diffMatch && !evidenceAvailable) {
   303|    violations.push({
   304|      rule: 'NO_CODE_CHANGE_WITHOUT_DIFF',
   305|      snippet: diffMatch[0],
   306|      reason: 'Contains diff-like syntax but no actual diff evidence exists.',
   307|    });
   308|  }
   309|
   310|  return violations;
   311|}
   312|
   313|// ---------------------------------------------------------------------------
   314|// Fake-deliverable scanner (no report-file/link/storage tool exists)
   315|// ---------------------------------------------------------------------------
   316|
   317|/**
   318| * Scan an answer for fake-deliverable claims:
   319| *  - placeholder / dead links (href "#", empty, void, example.com, localhost)
   320| *  - "report/file is ready/finalized/generated" with no real deliverable
   321| *  - deferred-delivery promises ("I'll deliver shortly", "30 more minutes")
   322| *
   323| * `hasRealDeliverable` is true ONLY when a real, attributable deliverable
   324| * (a reachable hosted file/link or a stored file reference) actually exists.
   325| * Placeholder/dead links are ALWAYS blocked regardless, because a real link
   326| * is never "#". IVX currently has no report-file-generation or file-hosting
   327| * tool, so `hasRealDeliverable` is false unless a caller proves otherwise.
   328| *
   329| * Pure function — deterministic, no I/O.
   330| */
   331|export function scanForFakeDeliverableClaims(
   332|  answer: string,
   333|  hasRealDeliverable: boolean,
   334|): ProhibitionViolation[] {
   335|  const violations: ProhibitionViolation[] = [];
   336|
   337|  const placeholder = PLACEHOLDER_LINK_REGEX.exec(answer);
   338|  if (placeholder) {
   339|    violations.push({
   340|      rule: 'NO_PLACEHOLDER_LINK',
   341|      snippet: placeholder[0],
   342|      reason:
   343|        'Contains a non-functional placeholder link (href "#"/empty/void). A deliverable link must point to a real, reachable file.',
   344|    });
   345|  }
   346|
   347|  const placeholderHref = PLACEHOLDER_HREF_REGEX.exec(answer);
   348|  if (placeholderHref) {
   349|    violations.push({
   350|      rule: 'NO_PLACEHOLDER_LINK',
   351|      snippet: placeholderHref[0],
   352|      reason:
   353|        'Contains a placeholder/example href (example.com / localhost / your-domain / TBD). Not a real deliverable.',
   354|    });
   355|  }
   356|
   357|  if (!hasRealDeliverable) {
   358|    const ready = DELIVERABLE_READY_REGEX.exec(answer);
   359|    if (ready) {
   360|      violations.push({
   361|        rule: 'NO_DELIVERABLE_WITHOUT_REAL_FILE',
   362|        snippet: ready[0],
   363|        reason:
   364|          'Claims a report/file/deliverable is ready but no real file or reachable link exists. IVX has no report-file-generation or file-hosting tool — return a VERIFIED failure reason instead.',
   365|      });
   366|    }
   367|
   368|    const deferred = DEFERRED_DELIVERY_REGEX.exec(answer);
   369|    if (deferred) {
   370|      violations.push({
   371|        rule: 'NO_UNFULFILLED_DELIVERY_PROMISE',
   372|        snippet: deferred[0],
   373|        reason:
   374|          'Promises a future deliverable ("will deliver / X more minutes / shortly") with no tracked job state. Either deliver now or return a VERIFIED failure reason.',
   375|      });
   376|    }
   377|
   378|    const timePromise = TIME_PROMISE_REGEX.exec(answer);
   379|    if (timePromise && DELIVERABLE_CONTEXT_REGEX.test(answer)) {
   380|      violations.push({
   381|        rule: 'NO_TIME_PROMISE',
   382|        snippet: timePromise[0],
   383|        reason:
   384|          'Open-ended time promise ("30 more minutes / shortly / almost done") for a deliverable with no tracked job. Not allowed.',
   385|      });
   386|    }
   387|  }
   388|
   389|  return violations;
   390|}
   391|
   392|/**
   393| * Scan an answer for fabricated live-query narrative — phrases that claim a SQL /
   394| * database query is being run mid-message when no real query actually executed
   395| * in this turn. A text model cannot run queries itself; real counts come only
   396| * from the IVX count tool. When `realQueryRan` is true (the count tool executed
   397| * a real query this turn), this narrative is legitimate and is not flagged.
   398| *
   399| * Pure function — deterministic, no I/O.
   400| */
   401|export function scanForUnbackedQueryNarrative(answer: string, realQueryRan: boolean): ProhibitionViolation[] {
   402|  if (realQueryRan) return [];
   403|  for (const regex of QUERY_NARRATIVE_REGEXES) {
   404|    const match = regex.exec(answer);
   405|    if (match) {
   406|      return [
   407|        {
   408|          rule: 'NO_QUERY_NARRATIVE_WITHOUT_EXECUTION',
   409|          snippet: match[0],
   410|          reason:
   411|            'Claims a database/SQL query is being run mid-message, but no real query executed this turn. A text model cannot run queries — use the IVX count tool or state the real number is unavailable.',
   412|        },
   413|      ];
   414|    }
   415|  }
   416|  return [];
   417|}
   418|
   419|/**
   420| * The honest message IVX returns when it tried to narrate running a query but no
   421| * real query executed. Used to rewrite fabricated "I'm running these queries
   422| * now" answers on the chat path.
   423| */
   424|export function buildNoLiveQueryMessage(): string {
   425|  return [
   426|    'I do not have a live count for that right now.',
   427|    '',
   428|    "I can't run a database query inside this reply, and the count tool did not return a verified number this turn (Supabase may be unconfigured, or the table may not exist in this project). Rather than give you a fabricated figure, I'm telling you straight: no exact count is available right now.",
   429|    '',
   430|    'Ask again and I will run a real count=exact query, or tell me the exact table to count.',
   431|  ].join('\n');
   432|}
   433|
   434|// ---------------------------------------------------------------------------
   435|// Claim extraction (requirement 1 — identify what the answer claims)
   436|// ---------------------------------------------------------------------------
   437|
   438|export type ExtractedClaim = {
   439|  category: ClaimCategory;
   440|  claimedText: string;
   441|};
   442|
   443|/**
   444| * Extract the technical claims present in an answer string.
   445| * Pure function — deterministic, no side effects.
   446| */
   447|export function extractClaims(answer: string): ExtractedClaim[] {
   448|  const claims: ExtractedClaim[] = [];
   449|
   450|  for (const match of answer.matchAll(new RegExp(CODE_CHANGE_REGEX.source, 'gi'))) {
   451|    claims.push({ category: CLAIM_CATEGORY.CODE_CHANGE, claimedText: match[0] });
   452|  }
   453|
   454|  for (const match of answer.matchAll(new RegExp(COMMIT_REGEX.source, 'gi'))) {
   455|    claims.push({ category: CLAIM_CATEGORY.GIT_COMMIT, claimedText: match[0] });
   456|  }
   457|
   458|  for (const match of answer.matchAll(new RegExp(DEPLOY_REGEX.source, 'gi'))) {
   459|    claims.push({ category: CLAIM_CATEGORY.DEPLOYMENT, claimedText: match[0] });
   460|  }
   461|
   462|  for (const match of answer.matchAll(new RegExp(DB_MUTATION_REGEX.source, 'gi'))) {
   463|    claims.push({ category: CLAIM_CATEGORY.DATABASE_MUTATION, claimedText: match[0] });
   464|  }
   465|
   466|  for (const match of answer.matchAll(new RegExp(TEST_RESULT_REGEX.source, 'gi'))) {
   467|    claims.push({ category: CLAIM_CATEGORY.TEST_RESULT, claimedText: match[0] });
   468|  }
   469|
   470|  return claims;
   471|}
   472|
   473|// ---------------------------------------------------------------------------
   474|// Evidence gate evaluation (requirement 1)
   475|// ---------------------------------------------------------------------------
   476|
   477|export type EvidenceGateResult = {
   478|  /** Whether the answer passes the evidence gate (no unbacked claims). */
   479|  passed: boolean;
   480|  /** All extracted claims with their evidence evaluation. */
   481|  claims: EvidenceClaim[];
   482|  /** Any prohibition violations found. */
   483|  violations: ProhibitionViolation[];
   484|  /** Overall label for the answer's strongest claim. */
   485|  overallLabel: EvidenceLabel;
   486|  /** Summary string for audit/internal logging. */
   487|  summary: string;
   488|};
   489|
   490|export type EvidenceGateInput = {
   491|  /** The answer text to validate. */
   492|  answer: string;
   493|  /** Whether the answer came from a real tool execution (not a simulated/LLM-only path). */
   494|  toolWasExecuted: boolean;
   495|  /** Evidence metadata from the tool execution (null if no tool was run). */
   496|  evidenceMetadata: EvidenceMetadata | null;
   497|  /** Whether repository access was verified (for developer-mode reports). */
   498|  repoAccessVerified: boolean;
   499|  /**
   500|   * Whether a real, attributable deliverable (reachable hosted file/link or a
   501|   * stored file reference) actually exists. Defaults to false — IVX has no
   502|   * report-file-generation or file-hosting tool, so deliverable/link claims
   503|   * are blocked unless a caller proves a real artifact exists.
   504|   */
   505|  hasRealDeliverable?: boolean;
   506|};
   507|
   508|/**
   509| * Evaluate an answer against the evidence gate.
   510| *
   511| * Returns a structured gate result. Claims without evidence are labelled
   512| * NOT_EXECUTED or UNVERIFIED; claims WITH evidence are labelled EXECUTED.
   513| * Prohibition violations are surfaced separately.
   514| *
   515| * Pure function — no I/O.
   516| */
   517|export function evaluateEvidenceGate(input: EvidenceGateInput): EvidenceGateResult {
   518|  const { answer, toolWasExecuted, evidenceMetadata, repoAccessVerified } = input;
   519|
   520|  const violations = [
   521|    ...scanForProhibitions(answer, toolWasExecuted),
   522|    ...scanForFakeDeliverableClaims(answer, input.hasRealDeliverable ?? false),
   523|  ];
   524|  const extractedClaims = extractClaims(answer);
   525|
   526|  const evidenceClaims: EvidenceClaim[] = extractedClaims.map((claim) => {
   527|    if (!toolWasExecuted) {
   528|      return {
   529|        category: claim.category,
   530|        claimedText: claim.claimedText,
   531|        evidencePresent: false,
   532|        metadata: null,
   533|        label: EVIDENCE_LABEL.NOT_EXECUTED,
   534|        reason: 'No tool was executed — the claim has zero backing evidence.',
   535|      };
   536|    }
   537|
   538|    if (!evidenceMetadata) {
   539|      return {
   540|        category: claim.category,
   541|        claimedText: claim.claimedText,
   542|        evidencePresent: false,
   543|        metadata: null,
   544|        label: EVIDENCE_LABEL.UNVERIFIED,
   545|        reason: 'A tool was run but evidence metadata is unavailable.',
   546|      };
   547|    }
   548|
   549|    return {
   550|      category: claim.category,
   551|      claimedText: claim.claimedText,
   552|      evidencePresent: true,
   553|      metadata: evidenceMetadata,
   554|      label: EVIDENCE_LABEL.EXECUTED,
   555|      reason: `Evidence captured by ${evidenceMetadata.toolName} at ${evidenceMetadata.timestamp} (ref: ${evidenceMetadata.rawOutputRef}).`,
   556|    };
   557|  });
   558|
   559|  // If no claims were extracted, the answer doesn't need evidence gating
   560|  const hasClaims = evidenceClaims.length > 0;
   561|  const hasViolations = violations.length > 0;
   562|  const passed = !hasViolations && (!hasClaims || evidenceClaims.every((c) => c.label === EVIDENCE_LABEL.EXECUTED));
   563|
   564|  // Overall label: strongest claim label (worst-first priority)
   565|  const overallLabel = hasClaims
   566|    ? evidenceClaims.some((c) => c.label === EVIDENCE_LABEL.NOT_EXECUTED)
   567|      ? EVIDENCE_LABEL.NOT_EXECUTED
   568|      : evidenceClaims.some((c) => c.label === EVIDENCE_LABEL.UNVERIFIED)
   569|        ? EVIDENCE_LABEL.UNVERIFIED
   570|        : evidenceClaims.some((c) => c.label === EVIDENCE_LABEL.SIMULATED)
   571|          ? EVIDENCE_LABEL.SIMULATED
   572|          : EVIDENCE_LABEL.EXECUTED
   573|    : toolWasExecuted
   574|      ? EVIDENCE_LABEL.EXECUTED
   575|      : EVIDENCE_LABEL.NOT_EXECUTED;
   576|
   577|  const summary = [
   578|    `Evidence gate: ${passed ? 'PASSED' : 'FAILED'}`,
   579|    `Claims: ${evidenceClaims.length} (${evidenceClaims.filter((c) => c.label === EVIDENCE_LABEL.EXECUTED).length} EXECUTED, ${evidenceClaims.filter((c) => c.label === EVIDENCE_LABEL.NOT_EXECUTED).length} NOT_EXECUTED, ${evidenceClaims.filter((c) => c.label === EVIDENCE_LABEL.UNVERIFIED).length} UNVERIFIED)`,
   580|    `Violations: ${violations.length}`,
   581|    `Overall: ${overallLabel}`,
   582|    `Tool executed: ${toolWasExecuted}`,
   583|    `Repo verified: ${repoAccessVerified}`,
   584|  ].join(' | ');
   585|
   586|  return { passed, claims: evidenceClaims, violations, overallLabel, summary };
   587|}
   588|
   589|// ---------------------------------------------------------------------------
   590|// Stream separation (requirement 5) — internal audit payload
   591|// ---------------------------------------------------------------------------
   592|
   593|export type InternalAuditPayload = {
   594|  stream: 'task_log' | 'watchdog' | 'tool_output' | 'audit_report';
   595|  requestId: string;
   596|  timestamp: string;
   597|  data: Record<string, unknown>;
   598|};
   599|
   600|export type UserVisiblePayload = {
   601|  stream: 'user_chat';
   602|  answer: string;
   603|  evidenceLabel: EvidenceLabel;
   604|  evidenceMetadata: EvidenceMetadata | null;
   605|};
   606|
   607|/**
   608| * Separate a response into internal (audit) and user-visible (chat) streams.
   609| * The user_chat stream always carries the evidence label so the UI can
   610| * surface it (e.g. "NOT EXECUTED" badge) without exposing internal details.
   611| *
   612| * Pure function — deterministic.
   613| */
   614|export function separateStreams(
   615|  userAnswer: string,
   616|  gateResult: EvidenceGateResult,
   617|  requestId: string,
   618|  toolOutput: Record<string, unknown> | null,
   619|): { userVisible: UserVisiblePayload; internal: InternalAuditPayload[] } {
   620|  const timestamp = new Date().toISOString();
   621|
   622|  const userVisible: UserVisiblePayload = {
   623|    stream: 'user_chat',
   624|    answer: userAnswer,
   625|    evidenceLabel: gateResult.overallLabel,
   626|    evidenceMetadata: gateResult.claims.find((c) => c.metadata)?.metadata ?? null,
   627|  };
   628|
   629|  const internal: InternalAuditPayload[] = [];
   630|
   631|  // task_log — the execution outcome
   632|  internal.push({
   633|    stream: 'task_log',
   634|    requestId,
   635|    timestamp,
   636|    data: {
   637|      gatePassed: gateResult.passed,
   638|      overallLabel: gateResult.overallLabel,
   639|      claimCount: gateResult.claims.length,
   640|      violationCount: gateResult.violations.length,
   641|    },
   642|  });
   643|
   644|  // watchdog — prohibitions
   645|  if (gateResult.violations.length > 0) {
   646|    internal.push({
   647|      stream: 'watchdog',
   648|      requestId,
   649|      timestamp,
   650|      data: {
   651|        violations: gateResult.violations.map((v) => ({ rule: v.rule, snippet: v.snippet, reason: v.reason })),
   652|      },
   653|    });
   654|  }
   655|
   656|  // tool_output — raw evidence
   657|  if (toolOutput) {
   658|    internal.push({
   659|      stream: 'tool_output',
   660|      requestId,
   661|      timestamp,
   662|      data: toolOutput,
   663|    });
   664|  }
   665|
   666|  // audit_report — full gate evaluation
   667|  internal.push({
   668|    stream: 'audit_report',
   669|    requestId,
   670|    timestamp,
   671|    data: {
   672|      summary: gateResult.summary,
   673|      claims: gateResult.claims.map((c) => ({
   674|        category: c.category,
   675|        claimedText: c.claimedText,
   676|        label: c.label,
   677|        reason: c.reason,
   678|      })),
   679|      violations: gateResult.violations,
   680|    },
   681|  });
   682|
   683|  return { userVisible, internal };
   684|}
   685|
   686|// ---------------------------------------------------------------------------
   687|// Developer-mode gate (requirement 6)
   688|// ---------------------------------------------------------------------------
   689|
   690|export type DeveloperModeGateResult = {
   691|  /** Whether the developer report is allowed. */
   692|  allowed: boolean;
   693|  /** Reason for denial (empty when allowed). */
   694|  reason: string;
   695|  /** The evidence gate result if a report was requested. */
   696|  gateResult: EvidenceGateResult | null;
   697|};
   698|
   699|/**
   700| * Gate for developer-mode reports. Reports are ONLY allowed after:
   701| * 1. Repository access has been verified, AND
   702| * 2. A tool was actually executed, AND
   703| * 3. Evidence was captured.
   704| *
   705| * Pure function.
   706| */
   707|export function gateDeveloperModeReport(
   708|  gateInput: EvidenceGateInput,
   709|  isDeveloperModeRequest: boolean,
   710|): DeveloperModeGateResult {
   711|  if (!isDeveloperModeRequest) {
   712|    return { allowed: true, reason: '', gateResult: null };
   713|  }
   714|
   715|  if (!gateInput.repoAccessVerified) {
   716|    return {
   717|      allowed: false,
   718|      reason: 'Developer mode report denied: repository access has not been verified.',
   719|      gateResult: evaluateEvidenceGate(gateInput),
   720|    };
   721|  }
   722|
   723|  if (!gateInput.toolWasExecuted) {
   724|    return {
   725|      allowed: false,
   726|      reason: 'Developer mode report denied: no tool was executed — cannot generate a developer report from simulated data.',
   727|      gateResult: evaluateEvidenceGate(gateInput),
   728|    };
   729|  }
   730|
   731|  if (!gateInput.evidenceMetadata) {
   732|    return {
   733|      allowed: false,
   734|      reason: 'Developer mode report denied: tool was executed but evidence metadata is unavailable.',
   735|      gateResult: evaluateEvidenceGate(gateInput),
   736|    };
   737|  }
   738|
   739|  return {
   740|    allowed: true,
   741|    reason: '',
   742|    gateResult: evaluateEvidenceGate(gateInput),
   743|  };
   744|}
   745|
   746|// ---------------------------------------------------------------------------
   747|// Answer injection — prepend evidence label when answer is NOT_EXECUTED
   748|// or UNVERIFIED (requirement 3: user-visible labelling)
   749|// ---------------------------------------------------------------------------
   750|
   751|/**
   752| * If the answer makes technical claims without evidence, inject a visible
   753| * label at the top of the answer so the user knows the claims are not verified.
   754| *
   755| * When the gate passes (EXECUTED), the answer is returned unchanged.
   756| *
   757| * Pure function.
   758| */
   759|export function applyEvidenceLabelToAnswer(answer: string, gateResult: EvidenceGateResult): string {
   760|  if (gateResult.overallLabel === EVIDENCE_LABEL.EXECUTED) {
   761|    // A technical claim backed by real evidence is classified VERIFIED (TASK 2).
   762|    // Non-technical answers (no claims) are returned unchanged.
   763|    if (gateResult.claims.length > 0) {
   764|      return `✅ VERIFIED — The technical claims in this response are backed by executed tool evidence.\n\n${answer}`;
   765|    }
   766|    return answer;
   767|  }
   768|
   769|  if (gateResult.overallLabel === EVIDENCE_LABEL.NOT_EXECUTED && gateResult.claims.length > 0) {
   770|    return `⚠️ NOT EXECUTED — The claims in this response are not backed by executed tool evidence.\n\n${answer}`;
   771|  }
   772|
   773|  if (gateResult.overallLabel === EVIDENCE_LABEL.UNVERIFIED && gateResult.claims.length > 0) {
   774|    return `⚠️ UNVERIFIED — Tool evidence for the claims in this response is unavailable.\n\n${answer}`;
   775|  }
   776|
   777|  if (gateResult.overallLabel === EVIDENCE_LABEL.SIMULATED) {
